1	import { useEffect, useState } from 'react';
2	import { useQueryClient } from '@tanstack/react-query';
3	import {
4	  AlertCircle,
5	  ArrowLeft,
6	  CheckCircle2,
7	  Clock,
8	  DoorOpen,
9	  Eye,
10	  RefreshCw,
11	} from 'lucide-react';
12	import {
13	  Button,
14	  Card,
15	  IconButton,
16	  Logo,
17	  SelectField,
18	  Skeleton,
19	  TextField,
20	} from '@/design/components';
21	import {
22	  ACTIVE_EID_KEY,
23	  ACTIVE_SNAPSHOT_KEY,
24	  REFRESH_ACTIVE,
25	  RpcError,
26	  rpc,
27	} from '@/lib/messaging';
28	import type { PreviewResponse } from '@/lib/types';
29	import {
30	  useActiveEid,
31	  useActiveSnapshot,
32	  useAuthStatus,
33	  useDraft,
34	  usePatchDraft,
35	  usePreview,
36	  useResolveEvent,
37	  useSend,
38	  useVisitorEvents,
39	} from './hooks';
40	import { AccountMenu } from './AccountMenu';
41	import { EmptyState } from './EmptyState';
42	import { RosterRow } from './RosterRow';
43	import { PreviewSheet } from './PreviewSheet';
44	import { SignInGate } from './SignInGate';
45	
46	const isAuthError = (err: unknown) => err instanceof RpcError && !!err.needsAuth;
47	
48	export function VisitPanel() {
49	  // `storedEid` is what the content script is pointing us at (auto-follow). We
50	  // freeze the *displayed* `eid` while busy so following never switches the view
51	  // mid-action (Guard 1); edits already persist on blur (Guard 2).
52	  const storedEid = useActiveEid();
53	  const snapshot = useActiveSnapshot();
54	  const [eid, setEid] = useState<string | null>(storedEid);
55	  const auth = useAuthStatus();
56	  // Picker fuels the "open from list" empty state (and graceful fallback).
57	  const visitorEvents = useVisitorEvents(!eid && !!auth.data?.signedIn);
58	  const resolve = useResolveEvent(eid);
59	  const event = resolve.data;
60	  const draft = useDraft(event);
61	
62	  const patch = usePatchDraft(event?.iCalUid);
63	  const send = useSend(event?.iCalUid, event?.start, event?.end);
64	  const preview = usePreview(event?.iCalUid);
65	
66	  const [previewData, setPreviewData] = useState<{
67	    preview: PreviewResponse;
68	    recipient: string;
69	  } | null>(null);
70	  const [location, setLocation] = useState<string | null>(null);
71	
72	  // Guard 1: hold the current event while sending / previewing; catch up once idle.
73	  const busy = send.isPending || preview.isPending || !!previewData;
74	  useEffect(() => {
75	    if (!busy) setEid(storedEid);
76	  }, [storedEid, busy]);
77	
78	  // Post-save refresh: the background sync poll broadcasts when the active event
79	  // changed on the server (no DOM); refetch so the roster reflects saved state.
80	  const qc = useQueryClient();
81	  useEffect(() => {
82	    const listener = (msg: { type?: string }) => {
83	      if (msg?.type === REFRESH_ACTIVE) {
84	        qc.invalidateQueries({ queryKey: ['resolve'] });
85	        qc.invalidateQueries({ queryKey: ['draft'] });
86	      }
87	    };
88	    chrome.runtime.onMessage.addListener(listener);
89	    return () => chrome.runtime.onMessage.removeListener(listener);
90	  }, [qc]);
91	
92	  // Back → clear the active event/snapshot, returning to the home list.
93	  const clearActive = () =>
94	    chrome.storage.session.remove([ACTIVE_EID_KEY, ACTIVE_SNAPSHOT_KEY]);
95	  // Show Back in every screen except the pure home (no event, no snapshot).
96	  const back = eid || snapshot?.magicPresent ? clearActive : undefined;
97	
98	  // ---- gating states ----
99	  if (!eid) {
100	    // New, not-yet-saved visitor event (no eid, but the DOM saw the magic
101	    // address) → preview the detected guests + prompt to save.
102	    if (snapshot?.magicPresent) {
103	      return (
104	        <Shell onBack={back}>
105	          <NoticeState
106	            title="Save the event to issue passes"
107	            body="This event isn’t saved yet, so passes can’t be issued. Add your guests and save it in Google Calendar, then reopen Manage Visitors."
108	            guests={snapshot.guestEmails}
109	          />
110	        </Shell>
111	      );
112	    }
113	    return (
114	      <Shell>
115	        <EmptyState
116	          auth={auth.data}
117	          events={visitorEvents.data}
118	          loading={visitorEvents.isLoading}
119	          onPick={(ev) => {
120	            chrome.storage.session.set({ [ACTIVE_EID_KEY]: ev.eid });
121	            // Idea 4: also open that event in the same calendar tab.
122	            void rpc({ type: 'NAVIGATE_TO_EVENT', eventId: ev.eventId });
123	          }}
124	        />
125	      </Shell>
126	    );
127	  }
128	  if (isAuthError(resolve.error) || isAuthError(draft.error)) {
129	    return <Shell onBack={back}><SignInGate /></Shell>;
130	  }
131	  if (resolve.isLoading) return <Shell onBack={back}><LoadingState label="Reading event…" /></Shell>;
132	  if (resolve.isError) {
133	    const msg = (resolve.error as Error).message;
134	    if (msg === 'NOT_SAVED') {
135	      return (
136	        <Shell onBack={back}>
137	          <NoticeState
138	            title="Save the event to issue passes"
139	            body="This event isn’t saved yet, so passes can’t be issued. Save it in Google Calendar, then reopen Manage Visitors."
140	            onRetry={() => resolve.refetch()}
141	            guests={snapshot?.guestEmails}
142	          />
143	        </Shell>
144	      );
145	    }
146	    return (
147	      <Shell onBack={back}>
148	        <ErrorState message={msg} onRetry={() => resolve.refetch()} />
149	      </Shell>
150	    );
151	  }
152	  // Event resolved but no iCalUID → the draft query can't run (would sit on a
153	  // skeleton forever). Surface it instead of hanging.
154	  if (event && !event.iCalUid) {
155	    return (
156	      <Shell onBack={back}>
157	        <NoticeState
158	          title="Can’t register from this event"
159	          body="This event has no calendar UID yet — usually because it isn’t fully saved. Save it in Google Calendar and try again."
160	          onRetry={() => resolve.refetch()}
161	        />
162	      </Shell>
163	    );
164	  }
165	  if (draft.isError) {
166	    return (
167	      <Shell onBack={back}>
168	        <ErrorState message={(draft.error as Error).message} onRetry={() => draft.refetch()} />
169	      </Shell>
170	    );
171	  }
172	  if (!draft.data) {
173	    return <Shell onBack={back}><RosterSkeleton title={event?.title} /></Shell>;
174	  }
175	
176	  const data = draft.data;
177	  const included = data.roster.filter((g) => g.include);
178	  const sentCount = data.roster.filter((g) => g.status === 'sent').length;
179	  const locValue = location ?? data.location ?? '';
180	
181	  const templates = data.emailTemplates;
182	  // One template for the whole event (engine stores per-guest; we set all guests
183	  // to the chosen key).
184	  const currentTemplate =
185	    data.roster.find((g) => g.emailTemplateKey)?.emailTemplateKey ??
186	    templates.find((t) => t.isDefault)?.key ??
187	    templates[0]?.key;
188	
189	  const patchGuest = (email: string, edit: Record<string, unknown>) =>
190	    patch.mutate({ guests: [{ email, ...edit }] });
191	
192	  const setEventTemplate = (key: string) =>
193	    patch.mutate({ guests: data.roster.map((g) => ({ email: g.email, emailTemplateKey: key })) });
194	
195	  // Review & send: render the real email for a representative included guest,
196	  // then Send/Cancel from the preview.
197	  const reviewEmail = included[0]?.email;
198	  const openReview = () => {
199	    if (!reviewEmail) return;
200	    preview.mutate(reviewEmail, {
201	      onSuccess: (d) => setPreviewData({ preview: d, recipient: reviewEmail }),
202	    });
203	  };
204	
205	  const canSend = (included.length > 0 || data.materialized) && !send.isPending;
206	  const reviewLabel = data.materialized ? 'Review & update passes' : 'Review & send passes';
207	
208	  return (
209	    <Shell onBack={back}>
210	      <div className="enter" style={{ padding: 'var(--space-lg)', display: 'grid', gap: 'var(--space-lg)' }}>
211	        <div
212	          className="type-label-sm text-muted"
213	          style={{ display: 'flex', alignItems: 'center', gap: 6 }}
214	        >
215	          <Eye size={13} strokeWidth={2} />
216	          Following the event open in Calendar
217	        </div>
218	        {/* Event summary */}
219	        <Card style={{ display: 'grid', gap: 'var(--space-sm)' }}>
220	          <div className="type-title-lg">{event?.title || 'Untitled event'}</div>
221	          {event?.start && (
222	            <div className="type-body text-muted" style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
223	              <Clock size={15} strokeWidth={2} />
224	              {formatWhen(event.start, event.end)}
225	            </div>
226	          )}
227	          {event?.rooms && event.rooms.length > 0 && (
228	            <div className="type-body text-muted" style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
229	              <DoorOpen size={15} strokeWidth={2} />
230	              <span className="row__ellipsis">{event.rooms.join(', ')}</span>
231	            </div>
232	          )}
233	          {event?.description && (
234	            <div
235	              className="type-label-sm text-muted"
236	              style={{
237	                whiteSpace: 'pre-wrap',
238	                maxHeight: 72,
239	                overflow: 'hidden',
240	                borderTop: '1px solid var(--color-outline-variant)',
241	                paddingTop: 'var(--space-sm)',
242	              }}
243	            >
244	              {event.description}
245	            </div>
246	          )}
247	          <TextField
248	            label="Where visitors check in"
249	            value={locValue}
250	            placeholder="e.g. Front desk, 3rd floor"
251	            onChange={(e) => setLocation(e.target.value)}
252	            onBlur={() =>
253	              locValue !== (data.location ?? '') && patch.mutate({ location: locValue })
254	            }
255	          />
256	          {templates.length >= 2 && (
257	            <SelectField
258	              label="Email template (all guests)"
259	              value={currentTemplate}
260	              onChange={(e) => setEventTemplate(e.target.value)}
261	            >
262	              {templates.map((t) => (
263	                <option key={t.key} value={t.key}>
264	                  {t.name}
265	                  {t.isDefault ? ' (default)' : ''}
266	                </option>
267	              ))}
268	            </SelectField>
269	          )}
270	        </Card>
271	
272	        {/* Roster */}
273	        <section>
274	          <div
275	            className="type-label-sm text-muted"
276	            style={{ textTransform: 'uppercase', marginBottom: 4 }}
277	          >
278	            Guests · {included.length} getting a pass
279	          </div>
280	          {data.roster.length === 0 ? (
281	            <Card className="type-body text-muted">
282	              No guests on this event yet. Add attendees in Calendar, then reopen.
283	            </Card>
284	          ) : (
285	            <Card style={{ paddingTop: 0, paddingBottom: 0 }}>
286	              {data.roster.map((g) => (
287	                <RosterRow
288	                  key={g.email}
289	                  guest={g}
290	                  onChange={(edit) => patchGuest(g.email, edit)}
291	                />
292	              ))}
293	            </Card>
294	          )}
295	        </section>
296	
297	        {/* Send result */}
298	        {send.isSuccess && <SendSummary result={send.data} />}
299	        {send.isError && (
300	          <div className="banner banner--error" role="alert">
301	            <AlertCircle size={18} strokeWidth={2} style={{ flex: '0 0 auto' }} />
302	            <span className="type-body">{(send.error as Error).message}</span>
303	          </div>
304	        )}
305	      </div>
306	
307	      {/* Sticky action bar */}
308	      <footer
309	        style={{
310	          padding: 'var(--space-md) var(--space-lg)',
311	          borderTop: '1px solid var(--color-outline-variant)',
312	          background: 'var(--color-surface-lowest)',
313	        }}
314	      >
315	        <Button
316	          block
317	          loading={preview.isPending}
318	          disabled={!canSend}
319	          icon={<Eye size={18} strokeWidth={2} />}
320	          onClick={openReview}
321	        >
322	          {preview.isPending
323	            ? 'Loading preview…'
324	            : `${reviewLabel}${included.length ? ` (${included.length})` : ''}`}
325	        </Button>
326	        {preview.isError && (
327	          <div className="type-label-sm" style={{ color: 'var(--color-error)', textAlign: 'center', marginTop: 6 }}>
328	            {(preview.error as Error).message}
329	          </div>
330	        )}
331	        {sentCount > 0 && !send.isPending && (
332	          <div className="type-label-sm text-muted" style={{ textAlign: 'center', marginTop: 6 }}>
333	            {sentCount} pass{sentCount > 1 ? 'es' : ''} already issued
334	          </div>
335	        )}
336	      </footer>
337	
338	      {previewData && (
339	        <PreviewSheet
340	          preview={previewData.preview}
341	          recipient={previewData.recipient}
342	          totalCount={included.length}
343	          sending={send.isPending}
344	          onSend={() =>
345	            send.mutate(undefined, { onSuccess: () => setPreviewData(null) })
346	          }
347	          onClose={() => setPreviewData(null)}
348	        />
349	      )}
350	    </Shell>
351	  );
352	}
353	
354	// ───────────────────────── sub-components ─────────────────────────
355	
356	function Shell({ children, onBack }: { children: React.ReactNode; onBack?: () => void }) {
357	  return (
358	    <div style={{ display: 'flex', flexDirection: 'column', height: '100%', minWidth: 320 }}>
359	      <header
360	        style={{
361	          display: 'flex',
362	          alignItems: 'center',
363	          gap: 'var(--space-sm)',
364	          padding: 'var(--space-md) var(--space-lg)',
365	          borderBottom: '1px solid var(--color-outline-variant)',
366	          flex: '0 0 auto',
367	        }}
368	      >
369	        {onBack ? (
370	          <IconButton label="Back to events" onClick={onBack}>
371	            <ArrowLeft size={20} strokeWidth={2} />
372	          </IconButton>
373	        ) : (
374	          <Logo size={26} />
375	        )}
376	        <span className="type-title">Auxilio Visitor</span>
377	        <span style={{ flex: 1 }} />
378	        <AccountMenu />
379	      </header>
380	      <div style={{ flex: 1, minHeight: 0, display: 'flex', flexDirection: 'column', overflowY: 'auto' }}>
381	        {children}
382	      </div>
383	    </div>
384	  );
385	}
386	
387	function LoadingState({ label }: { label: string }) {
388	  return (
389	    <div
390	      style={{
391	        flex: 1,
392	        display: 'flex',
393	        flexDirection: 'column',
394	        alignItems: 'center',
395	        justifyContent: 'center',
396	        gap: 'var(--space-md)',
397	        color: 'var(--color-on-surface-variant)',
398	      }}
399	    >
400	      <span className="spinner" style={{ width: 22, height: 22 }} />
401	      <span className="type-body">{label}</span>
402	    </div>
403	  );
404	}
405	
406	function RosterSkeleton({ title }: { title?: string }) {
407	  return (
408	    <div style={{ padding: 'var(--space-lg)', display: 'grid', gap: 'var(--space-lg)' }}>
409	      <Card style={{ display: 'grid', gap: 8 }}>
410	        <span className="type-title-lg">{title || 'Loading event…'}</span>
411	        <Skeleton width="60%" />
412	      </Card>
413	      <Card style={{ display: 'grid', gap: 'var(--space-lg)' }}>
414	        {[0, 1, 2].map((i) => (
415	          <div key={i} style={{ display: 'flex', gap: 'var(--space-md)', alignItems: 'center' }}>
416	            <Skeleton width={44} height={24} radius={999} />
417	            <div style={{ flex: 1, display: 'grid', gap: 6 }}>
418	              <Skeleton width="50%" />
419	              <Skeleton width="70%" height={12} />
420	            </div>
421	          </div>
422	        ))}
423	      </Card>
424	    </div>
425	  );
426	}
427	
428	function NoticeState({
429	  title,
430	  body,
431	  onRetry,
432	  guests,
433	}: {
434	  title: string;
435	  body: string;
436	  onRetry?: () => void;
437	  guests?: string[];
438	}) {
439	  return (
440	    <div style={{ padding: 'var(--space-lg)', display: 'grid', gap: 'var(--space-md)' }}>
441	      <Card style={{ display: 'grid', gap: 'var(--space-sm)', padding: 'var(--space-xl)' }}>
442	        <span className="type-title-lg">{title}</span>
443	        <span className="type-body text-muted">{body}</span>
444	        {onRetry && (
445	          <Button
446	            variant="tonal"
447	            icon={<RefreshCw size={16} strokeWidth={2} />}
448	            onClick={onRetry}
449	            style={{ justifySelf: 'start', marginTop: 'var(--space-xs)' }}
450	          >
451	            Check again
452	          </Button>
453	        )}
454	      </Card>
455	      {guests && guests.length > 0 && (
456	        <Card style={{ display: 'grid', gap: 'var(--space-xs)' }}>
457	          <span className="type-label-sm text-muted" style={{ textTransform: 'uppercase' }}>
458	            Guests detected on this event
459	          </span>
460	          {guests.map((g) => (
461	            <span key={g} className="type-body row__ellipsis">{g}</span>
462	          ))}
463	        </Card>
464	      )}
465	    </div>
466	  );
467	}
468	
469	function ErrorState({ message, onRetry }: { message: string; onRetry: () => void }) {
470	  return (
471	    <div style={{ padding: 'var(--space-lg)' }}>
472	      <div className="banner banner--error" role="alert" style={{ marginBottom: 'var(--space-md)' }}>
473	        <AlertCircle size={18} strokeWidth={2} style={{ flex: '0 0 auto' }} />
474	        <span className="type-body">{message}</span>
475	      </div>
476	      <Button variant="tonal" icon={<RefreshCw size={16} strokeWidth={2} />} onClick={onRetry}>
477	        Try again
478	      </Button>
479	    </div>
480	  );
481	}
482	
483	function SendSummary({
484	  result,
485	}: {
486	  result: import('@/lib/types').SendResponse;
487	}) {
488	  return (
489	    <div
490	      className="banner"
