}
.guest + .guest { border-top: 1px solid var(--color-outline-variant); }
.guest--dim { opacity: 0.6; }

.guest__head {
  display: flex;
  align-items: center;
  gap: var(--space-md);
}

.guest__avatar {
  flex: 0 0 auto;
  width: 36px;
  height: 36px;
  border-radius: 50%;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  font-size: 13px;
  font-weight: 600;
  letter-spacing: 0.3px;
  background: var(--color-primary-container);
  color: var(--color-on-primary-container);
  user-select: none;
  transition: background-color var(--motion-base) var(--motion-easing),
    color var(--motion-base) var(--motion-easing);
}
.guest__avatar--sent { background: var(--color-success-container); color: var(--color-on-success-container); }
.guest__avatar--dim { background: var(--color-surface-high); color: var(--color-on-surface-variant); }

.guest__id { flex: 1 1 auto; min-width: 0; }
.guest__name { display: flex; align-items: center; gap: var(--space-xs); }

/* Inline edit form, recessed under the identity so it reads as "this guest's
   details" rather than free-floating inputs. Indented to align under the name. */
.guest__form {
  display: grid;
  gap: var(--space-sm);
  margin: var(--space-sm) 0 var(--space-xs) calc(36px + var(--space-md));
  padding: var(--space-md);
  background: var(--color-surface-low);
  border-radius: var(--radius-md);
  animation: guest-expand var(--motion-base) var(--motion-easing) both;
}
.guest__hint {
  margin: var(--space-xs) 0 0 calc(36px + var(--space-md));
  color: var(--color-on-surface-variant);
  font-weight: 500;
}
@keyframes guest-expand {
  from { opacity: 0; transform: translateY(-4px); }
  to { opacity: 1; transform: none; }
}

