1	/**
2	 * Calendar sync (background only). The durable, official "what changed" engine:
3	 * runs on a chrome.alarm, lists changes via a sync token, and maintains the set
4	 * of upcoming visitor (magic-address) events in storage.local. Drives:
5	 *  - post-save refresh of the open event (changedIds),
6	 *  - the visitor-event notification + toolbar badge (newMarked / count),
7	 *  - the side panel's "open from list" picker (listMarked).
8	 * No DOM. Reflects SAVED state only (pre-save edits are add-on-only — see
9	 * Planning-docs/2026-06-19_calendar_addon_vs_extension_capabilities.md).
10	 */
11	import { encodeEid, isMarked, listEvents } from './calendar';
12	import type { VisitorEventSummary } from './types';
13	
14	const SYNC_TOKEN_KEY = 'auxilio.syncToken';
15	const MARKED_KEY = 'auxilio.markedEvents';
16	const PAST_GRACE_MS = 60 * 60_000; // keep events until 1h after they end
17	
18	type MarkedMap = Record<string, VisitorEventSummary>;
19	
20	async function readMarked(): Promise<MarkedMap> {
21	  const r = await chrome.storage.local.get(MARKED_KEY);
22	  return (r[MARKED_KEY] as MarkedMap) ?? {};
23	}
24	
25	export interface SyncResult {
26	  changedIds: Set<string>;
27	  newMarked: VisitorEventSummary[];
28	  markedCount: number;
29	}
30	
31	/** Pull changes since the last sync; update the marked set; report deltas. */
32	export async function runSync(accessToken: string): Promise<SyncResult> {
33	  const store = await chrome.storage.local.get([SYNC_TOKEN_KEY, MARKED_KEY]);
34	  let syncToken = store[SYNC_TOKEN_KEY] as string | undefined;
35	  let marked = (store[MARKED_KEY] as MarkedMap) ?? {};
36	
37	  let resp = await listEvents(accessToken, { syncToken });
38	  if (resp.expired) {
39	    // Token stale → full resync from scratch.
40	    syncToken = undefined;
41	    marked = {};
42	    resp = await listEvents(accessToken, {});
43	  }
44	
45	  const changedIds = new Set<string>();
46	  const newMarked: VisitorEventSummary[] = [];
47	
48	  for (const ev of resp.items) {
49	    if (!ev.id) continue;
50	    changedIds.add(ev.id);
51	    const cancelled = ev.status === 'cancelled';
52	    if (isMarked(ev) && !cancelled) {
53	      const summary: VisitorEventSummary = {
54	        eid: encodeEid(ev.id, 'primary'),
55	        eventId: ev.id,
56	        iCalUid: ev.iCalUID ?? '',
57	        title: ev.summary || '(no title)',
58	        start: ev.start?.dateTime ?? ev.start?.date,
59	      };
60	      if (!marked[ev.id]) newMarked.push(summary);
61	      marked[ev.id] = summary;
62	    } else {
63	      delete marked[ev.id]; // unmarked or cancelled
64	    }
65	  }
66	
67	  // Prune events that are well past.
68	  const cutoff = Date.now() - PAST_GRACE_MS;
69	  for (const id of Object.keys(marked)) {
70	    const s = marked[id].start;
71	    if (s && Date.parse(s) < cutoff) delete marked[id];
72	  }
73	
74	  await chrome.storage.local.set({
75	    [SYNC_TOKEN_KEY]: resp.nextSyncToken ?? syncToken,
76	    [MARKED_KEY]: marked,
77	  });
78	
79	  return { changedIds, newMarked, markedCount: Object.keys(marked).length };
80	}
81	
82	/** Upcoming visitor events, soonest first — for the panel's picker. */
83	export async function listMarked(): Promise<VisitorEventSummary[]> {
84	  const marked = await readMarked();
85	  return Object.values(marked).sort((a, b) =>
86	    (a.start ?? '').localeCompare(b.start ?? ''),
87	  );
88	}
89	
90	/** Is this event id currently a known visitor event? */
91	export async function isEventMarked(eventId: string): Promise<boolean> {
92	  const marked = await readMarked();
93	  return !!marked[eventId];
94	}
