308	/**
309	 * Button UI manager (Idea 2): renders a NATIVE-styled button injected at a clean
310	 * anchor (next to Save on the /eventedit page) when one is found, and otherwise
311	 * falls back to a floating button. `update(show)` decides per render.
312	 */
313	function createButtonUI(onClick: () => void) {
314	  const fab = mountFloating(onClick);
315	  let injected: HTMLButtonElement | null = null;
316	
317	  /** A clean injection anchor, or null. Text/ARIA-based, never CSS classes. */
318	  function findAnchor(): { insert: (el: HTMLElement) => void } | null {
319	    // Edit page: place our button right before the native "Save" button.
320	    if (/\/eventedit/.test(location.pathname)) {
321	      const save = findButtonByText('save');
322	      const parent = save?.parentElement;
323	      if (save && parent) {
324	        return { insert: (el) => parent.insertBefore(el, save) };
325	      }
326	    }
327	    return null; // popover/modal → fall back to floating
328	  }
329	
330	  function ensureInjected(): boolean {
331	    const anchor = findAnchor();
332	    if (!anchor) return false;
333	    if (injected && injected.isConnected) return true; // still placed
334	    removeInjected();
335	    injected = buildInjectedButton(onClick);
336	    anchor.insert(injected);
337	    return true;
338	  }
339	
340	  function removeInjected() {
341	    injected?.remove();
342	    injected = null;
343	  }
344	
345	  return {
346	    update(show: boolean) {
347	      if (!show) {
348	        removeInjected();
349	        fab.setVisible(false);
350	        return;
351	      }
352	      const placed = ensureInjected();
353	      fab.setVisible(!placed); // floating only when we couldn't inject natively
354	    },
355	  };
356	}
357	
358	/** Find a clickable element whose visible text matches (case-insensitive). */
