function createButtonUI(onClick: () => void) {
  const fab = mountFloating(onClick);
  let injected: HTMLButtonElement | null = null;

  /** A clean injection anchor, or null. Text/ARIA-based, never CSS classes. */
  function findAnchor(): { insert: (el: HTMLElement) => void } | null {
