function createButtonUI(onClick: () => void) {
  const fab = mountFloating(onClick);
  let injected: HTMLButtonElement | null = null;

  type Anchor = { insert: (el: HTMLElement) => void; block: boolean };

  /** A clean injection anchor, or null. Text/ARIA-based, never CSS classes, so
   *  we stay decoupled from Google's obfuscated markup. Prefers the user-facing
   *  spots: above Description on the edit page, below the organiser in the
   *  detail popover. Falls back to the floating button only when neither fits. */
  function findAnchor(): Anchor | null {
    // Full-screen edit page → just above the Description section.
    if (/\/eventedit/.test(location.pathname)) {
      const desc = findEditDescription();
      if (desc) {
        const section = sectionAncestor(desc);
        const parent = section.parentElement;
        if (parent) return { insert: (el) => parent.insertBefore(el, section), block: true };
      }
      // Fallback within the edit page: right before the native "Save" button.
      const save = findButtonByText('save');
      const parent = save?.parentElement;
      if (save && parent) return { insert: (el) => parent.insertBefore(el, save), block: false };
      return null;
    }
    // Detail popover / modal → at the bottom, just below the organiser line.
    const dialog = document.querySelector<HTMLElement>('[role="dialog"]');
    if (dialog) {
      const org = findOrganiserRow(dialog);
      const parent = org?.parentElement;
      if (org && parent) {
        return { insert: (el) => parent.insertBefore(el, org.nextSibling), block: true };
      }
      // No organiser line found → append at the very bottom of the dialog.
      return { insert: (el) => dialog.appendChild(el), block: true };
    }
    return null;
  }

  function ensureInjected(): boolean {
    const anchor = findAnchor();
    if (!anchor) return false;
    if (injected && injected.isConnected) return true; // still placed
    removeInjected();
    injected = buildInjectedButton(onClick, anchor.block);
    anchor.insert(injected);
    return true;
  }

