/**
 * Button UI manager (Idea 2): renders a NATIVE-styled button injected at a clean
 * anchor (next to Save on the /eventedit page) when one is found, and otherwise
 * falls back to a floating button. `update(show)` decides per render.
 */
function createButtonUI(onClick: () => void) {
  const fab = mountFloating(onClick);
  let injected: HTMLButtonElement | null = null;

  type Anchor = { insert: (el: HTMLElement) => void; block: boolean };

  /** A clean injection anchor, or null. Text/ARIA-based, never CSS classes, so
   *  we stay decoupled from Google's obfuscated markup. Prefers the user-facing
   *  spots: above Description on the edit page, below the organiser in the
   *  detail popover. Falls back to the floating button only when neither fits. */
  function findAnchor(): Anchor | null {
    // Full-screen edit page → just above the Description section.
    if (/\/eventedit/.test(location.pathname)) {
      const desc = findEditDescription();
      if (desc) {
        const section = sectionAncestor(desc);
        const parent = section.parentElement;
        if (parent) return { insert: (el) => parent.insertBefore(el, section), block: true };
      }
      // Fallback within the edit page: right before the native "Save" button.
      const save = findButtonByText('save');
      const parent = save?.parentElement;
      if (save && parent) return { insert: (el) => parent.insertBefore(el, save), block: false };
      return null;
    }
    // Detail popover / modal → at the bottom, just below the organiser line.
    const dialog = document.querySelector<HTMLElement>('[role="dialog"]');
    if (dialog) {
      const org = findOrganiserRow(dialog);
      const parent = org?.parentElement;
      if (org && parent) {
        return { insert: (el) => parent.insertBefore(el, org.nextSibling), block: true };
      }
      // No organiser line found → append at the very bottom of the dialog.
      return { insert: (el) => dialog.appendChild(el), block: true };
    }
    return null;
  }

  function ensureInjected(): boolean {
    if (injected && injected.isConnected) return true; // still placed — skip the scan
    const anchor = findAnchor();
    if (!anchor) return false;
    removeInjected();
    injected = buildInjectedButton(onClick, anchor.block);
    anchor.insert(injected);
    return true;
  }

  function removeInjected() {
    injected?.remove();
    injected = null;
  }

  return {
    update(show: boolean) {
      if (!show) {
        removeInjected();
        fab.setVisible(false);
        return;
      }
      const placed = ensureInjected();
      fab.setVisible(!placed); // floating only when we couldn't inject natively
    },
  };
}

/** Find a clickable element whose visible text matches (case-insensitive). */
function findButtonByText(text: string): HTMLElement | null {
  const wanted = text.toLowerCase();
  const els = document.querySelectorAll<HTMLElement>('button,[role="button"]');
  for (const el of els) {
    if ((el.textContent ?? '').trim().toLowerCase() === wanted) return el;
  }
  return null;
}

const isVisible = (el: HTMLElement) => el.offsetParent !== null || el.getClientRects().length > 0;

/** The Description editor on the event edit page. ARIA/placeholder text only —
 *  never CSS classes (Google's are obfuscated and churn). */
function findEditDescription(): HTMLElement | null {
  const els = document.querySelectorAll<HTMLElement>(
    '[aria-label*="description" i], [placeholder*="description" i]',
  );
  for (const el of els) if (isVisible(el)) return el;
  return null;
}

/** Climb from a field to its "section row" — the child of the form's sections
 *  list — so we can insert a sibling *above the whole block*, not inside it. The
 *  sections list is the first ancestor with several element children. */
function sectionAncestor(el: HTMLElement): HTMLElement {
  let node: HTMLElement = el;
  while (node.parentElement && node.parentElement !== document.body) {
    if (node.parentElement.childElementCount >= 3) return node;
    node = node.parentElement;
  }
  return node;
}

/** The organiser line inside the detail popover, or null. Matches the visible
 *  "Organiser/Organizer" label, then returns its section row so we can drop the
 *  button right below it. */
function findOrganiserRow(dialog: HTMLElement): HTMLElement | null {
  const els = dialog.querySelectorAll<HTMLElement>('*');
  for (const el of els) {
    const t = (el.textContent ?? '').trim().toLowerCase();
    if ((t === 'organiser' || t === 'organizer') && isVisible(el)) {
      return sectionAncestor(el);
    }
  }
  return null;
}

