/** Climb from a field to its "section row" — the child of the form's sections
 *  list — so we can insert a sibling *between sections*, not inside one. The
 *  sections list is the first ancestor with several element children. */
function sectionAncestor(el: HTMLElement): HTMLElement {
  let node: HTMLElement = el;
  while (node.parentElement && node.parentElement !== document.body) {
    if (node.parentElement.childElementCount >= 3) return node;
    node = node.parentElement;
  }
  return node;
}

/** Horizontal gap between a section row's left edge and where its content
 *  begins (Google indents content past a leading icon gutter). Lets our row
 *  line up with the native fields instead of starting at the icon. */
function contentInset(row: HTMLElement, content: HTMLElement): number {
  const gap = content.getBoundingClientRect().left - row.getBoundingClientRect().left;
  return Number.isFinite(gap) && gap > 0 && gap < 120 ? Math.round(gap) : 0;
}

/** The organiser label inside the detail popover, or null. Matches the visible
 *  "Organiser/Organizer" text so we can sit our row just below that line. */
function findOrganiserLabel(dialog: HTMLElement): HTMLElement | null {
  const els = dialog.querySelectorAll<HTMLElement>('*');
  for (const el of els) {
    const t = (el.textContent ?? '').trim().toLowerCase();
    if ((t === 'organiser' || t === 'organizer') && isVisible(el)) return el;
  }
  return null;
}

