function findAnchor(): Anchor | null {
  // Full-screen edit page → a row of its own *between* Description and the
  // following section (e.g. Visibility).
  if (/\/eventedit/.test(location.pathname)) {
    const desc = findEditDescription();
    if (desc) {
      const section = sectionAncestor(desc);
      const parent = section.parentElement;
      if (parent) {
        const inset = contentInset(section, desc);
        return { insert: (el) => parent.insertBefore(el, section.nextSibling), inset };
      }
    }
    // Fallback within the edit page: inline, right before the native "Save".
    const save = findButtonByText('save');
    const parent = save?.parentElement;
    if (save && parent) return { insert: (el) => parent.insertBefore(el, save), inset: 0, inline: true };
    return null;
  }
  // Detail popover / modal → the LAST row of the content list, aligned under
  // the organiser line above it.
  const dialog = document.querySelector<HTMLElement>('[role="dialog"]');
  if (dialog) {
    const org = findOrganiserLabel(dialog);
    if (org) {
      const row = sectionAncestor(org);
      const list = row.parentElement;
      if (list) {
        const inset = contentInset(row, org);
        return { insert: (el) => list.appendChild(el), inset };
      }
    }
    // No organiser line found → append at the very bottom of the dialog.
    return { insert: (el) => dialog.appendChild(el), inset: 0 };
  }
  return null;
}

