/** Does this element stack its visible children vertically (a column of rows),
 *  rather than laying them out side by side? Geometry, not CSS classes. */
function stacksVertically(el: HTMLElement): boolean {
  const kids = [...el.children].filter((c): c is HTMLElement => c instanceof HTMLElement && isVisible(c));
  if (kids.length < 2) return false;
  for (let i = 1; i < kids.length; i++) {
    const a = kids[i - 1].getBoundingClientRect();
    const b = kids[i].getBoundingClientRect();
    if (b.top >= a.bottom - 2) return true; // the next child starts below the previous
  }
  return false;
}

/** Climb from a field to its full-width "section row" — the topmost ancestor
 *  that fills its parent's width AND whose parent stacks its children into a
 *  column. That parent is the vertical sections list; the returned node is the
 *  row we sit a sibling next to (so our button is its own row, never inline). */
function fullRowAncestor(el: HTMLElement): HTMLElement {
  let node: HTMLElement = el;
  let best: HTMLElement = el;
  while (node.parentElement && node.parentElement !== document.body) {
    const parent = node.parentElement;
    const nodeW = node.getBoundingClientRect().width;
    const parentW = parent.getBoundingClientRect().width;
    if (parentW > 0 && nodeW >= parentW * 0.8 && stacksVertically(parent)) best = node;
    node = parent;
  }
  return best;
}

/** The biggest vertically-stacking container inside `root` — the content column
 *  whose last child is the visual bottom of the surface. */
function mainVerticalList(root: HTMLElement): HTMLElement | null {
  let best: HTMLElement | null = null;
  let bestArea = 0;
  for (const el of root.querySelectorAll<HTMLElement>('*')) {
    if (!isVisible(el) || !stacksVertically(el)) continue;
    const r = el.getBoundingClientRect();
    const area = r.width * r.height;
    if (area > bestArea) {
      bestArea = area;
      best = el;
    }
  }
  return best;
}

