/** Horizontal gap between a section row's left edge and where its content
 *  begins (Google indents content past a leading icon gutter). Lets our row
 *  line up with the native fields instead of starting at the icon. */
function contentInset(row: HTMLElement, content: HTMLElement): number {
  const gap = content.getBoundingClientRect().left - row.getBoundingClientRect().left;
  return Number.isFinite(gap) && gap > 0 && gap < 120 ? Math.round(gap) : 0;
}

input.new_string:
/** Horizontal gap between a container's left edge and where the field content
 *  begins (Google indents content past a leading icon gutter). Lets our row
 *  line up with the native fields instead of starting at the icon. */
function contentInset(container: HTMLElement, content: HTMLElement): number {
  const gap = content.getBoundingClientRect().left - container.getBoundingClientRect().left;
  return Number.isFinite(gap) && gap > 0 && gap < 240 ? Math.round(gap) : 0;
}

/** The scrolling content region inside a surface (overflow-y auto/scroll),
 *  largest first — so our row lives with the content and scrolls, not in a
 *  pinned header/footer. Null when nothing scrolls. */
function scrollContainer(root: HTMLElement): HTMLElement | null {
  let best: HTMLElement | null = null;
  let bestArea = 0;
  for (const el of root.querySelectorAll<HTMLElement>('*')) {
    if (!isVisible(el)) continue;
    const oy = getComputedStyle(el).overflowY;
    if (oy !== 'auto' && oy !== 'scroll') continue;
    const r = el.getBoundingClientRect();
    const area = r.width * r.height;
    if (area > bestArea) {
      bestArea = area;
      best = el;
    }
  }
  return best;
}

