function findAnchor(): Anchor | null {
  // Full-screen edit page → our own row ABOVE the Description section.
  if (/\/eventedit/.test(location.pathname)) {
    const desc = findEditDescription();
    const found = desc && rowsListFor(desc);
    if (found) {
      const { list, row } = found;
      return { insert: (el) => list.insertBefore(el, row), inset: rowInset(row, list) };
    }
    // Fallback within the edit page: inline, right before the native "Save".
    const save = findButtonByText('save');
    const parent = save?.parentElement;
    if (save && parent) return { insert: (el) => parent.insertBefore(el, save), inset: 0, inline: true };
    return null;
  }
  // Detail popover / modal → our own row at the BOTTOM of the content list
  // (after the last row). The rows scroll, so it moves with the UI.
  const dialog = document.querySelector<HTMLElement>('[role="dialog"]');
  if (dialog) {
    const org = findOrganiserLabel(dialog);
    const found = org && rowsListFor(org);
    if (found) {
      const { list, row } = found;
      return { insert: (el) => list.appendChild(el), inset: rowInset(row, list) };
    }
    // No organiser row recognised → bottom of the scrolling content.
    const scope = scrollContainer(dialog) ?? dialog;
    const list = mainVerticalList(scope) ?? scope;
    return { insert: (el) => list.appendChild(el), inset: 0 };
  }
  return null;
}

