/** The organiser line inside the detail popover, or null. Matches the visible
 *  "Organiser/Organizer: <name>" text (shortest match = the leaf label) so we
 *  can anchor our row to the organiser's content row. */
function findOrganiserLabel(dialog: HTMLElement): HTMLElement | null {
  let best: HTMLElement | null = null;
  let bestLen = Infinity;
  for (const el of dialog.querySelectorAll<HTMLElement>('*')) {
    const t = (el.textContent ?? '').trim();
    const lc = t.toLowerCase();
    if ((lc.startsWith('organiser') || lc.startsWith('organizer')) && isVisible(el) && t.length < bestLen) {
      best = el;
      bestLen = t.length;
    }
  }
  return best;
}

